/* =============================================================
   CVU Research Library — Combined Widget Script
   Loaded via Higher Logic JavaScript widget "Enter URL" field.
   Contains: Google Fonts loader, PDF.js loader, all state,
   all functions, DOM-ready wiring, and all paper data.
   No HTML. No CSS. Safe from WYSIWYG editor corruption.
   ============================================================= */

// ── 1. Google Fonts (Inter) ──────────────────────────────────
(function() {
  var l = document.createElement('link');
  l.rel = 'stylesheet';
  l.href = 'https://fonts.googleapis.com/css2?family=Inter:wght@400;500;600;700&display=swap';
  document.head.appendChild(l);
})();

// ── 2. Config ────────────────────────────────────────────────
var CVU_CONFIG = {
  PER_PAGE:       24,
  PDF_WORKER_SRC: 'https://cdnjs.cloudflare.com/ajax/libs/pdf.js/3.11.174/pdf.worker.min.js',
  PDF_JS_SRC:     'https://cdnjs.cloudflare.com/ajax/libs/pdf.js/3.11.174/pdf.min.js',
  PDF_PROXY:      'https://verticalurbanism.org/?cvu_pdf='
};

// ── 3. State ─────────────────────────────────────────────────
var allPapers     = [];
var filtered      = [];
var page          = 1;
var view          = 'grid';
var selCat        = null;
var selSub        = null;
var selTopics     = {};   // object used as a Set (key=topic, val=true)
var searchQ       = '';
var sortBy        = 'year-desc';
var thumbCache    = {};
var thumbObserver = null;
var searchTimer   = null;

// ── 4. Utility helpers ───────────────────────────────────────
function esc(s) {
  if (s == null) return '';
  return String(s)
    .replace(/&/g, '&amp;')
    .replace(/</g, '&lt;')
    .replace(/>/g, '&gt;')
    .replace(/"/g, '&quot;')
    .replace(/'/g, '&#39;');
}

function sortedUnique(arr) {
  var seen = {};
  var out = [];
  for (var i = 0; i < arr.length; i++) {
    if (arr[i] && !seen[arr[i]]) { seen[arr[i]] = true; out.push(arr[i]); }
  }
  return out.sort(function(a, b) { return a.localeCompare(b); });
}

function topicsOf(p) {
  if (!p.tp) return [];
  return p.tp.split(',').map(function(t) { return t.trim(); });
}

// ── 5. Sidebar ───────────────────────────────────────────────
function buildSidebar() {
  var cats   = [];
  var subs   = [];
  var topics = [];
  for (var i = 0; i < allPapers.length; i++) {
    var p = allPapers[i];
    if (p.c) cats.push(p.c);
    if (p.s) subs.push(p.s);
    var tp = topicsOf(p);
    for (var j = 0; j < tp.length; j++) topics.push(tp[j]);
  }
  cats   = sortedUnique(cats);
  subs   = sortedUnique(subs);
  topics = sortedUnique(topics);

  function countOf(field, val) {
    var n = 0;
    for (var i = 0; i < allPapers.length; i++) {
      if (allPapers[i][field] === val) n++;
    }
    return n;
  }
  function countTopic(val) {
    var n = 0;
    for (var i = 0; i < allPapers.length; i++) {
      var tp = topicsOf(allPapers[i]);
      for (var j = 0; j < tp.length; j++) {
        if (tp[j] === val) { n++; break; }
      }
    }
    return n;
  }

  renderOpts('opts-cat', cats, function(v) { return countOf('c', v); }, 'cat', false);
  renderOpts('opts-sub', subs, function(v) { return countOf('s', v); }, 'sub', false);
  renderOpts('opts-tp',  topics, countTopic, 'tp', true);
}

function renderOpts(containerId, values, countFn, key, isMulti) {
  var el = document.getElementById(containerId);
  if (!el) return;
  var html = '';
  for (var i = 0; i < values.length; i++) {
    var v = values[i];
    html += '<div class="fopt" data-key="' + esc(key) + '" data-val="' + esc(v) + '">' +
            '<div class="fopt-box ' + (isMulti ? '' : 'fopt-circle') + '"></div>' +
            '<span class="fopt-label">' + esc(v) + '</span>' +
            '<span class="fopt-count">' + countFn(v) + '</span>' +
            '</div>';
  }
  el.innerHTML = html;

  el.addEventListener('click', function(e) {
    var fopt = e.target;
    while (fopt && !fopt.classList.contains('fopt')) fopt = fopt.parentElement;
    if (!fopt) return;
    if (isMulti) toggleTopic(fopt.dataset.val);
    else setSingle(key, fopt.dataset.val);
  });
}

// ── 6. Filter + Sort ─────────────────────────────────────────
function applyFilters() {
  var q = searchQ.toLowerCase();
  filtered = [];
  for (var i = 0; i < allPapers.length; i++) {
    var p = allPapers[i];
    if (selCat && p.c !== selCat) continue;
    if (selSub && p.s !== selSub) continue;
    if (Object.keys(selTopics).length > 0) {
      var pt = topicsOf(p);
      var match = false;
      for (var k in selTopics) {
        for (var j = 0; j < pt.length; j++) {
          if (pt[j] === k) { match = true; break; }
        }
        if (match) break;
      }
      if (!match) continue;
    }
    if (q) {
      var hay = ((p.t || '') + ' ' + (p.l1 || '') + ' ' + (p.l2 || '')).toLowerCase();
      if (hay.indexOf(q) === -1) continue;
    }
    filtered.push(p);
  }

  // Sort
  filtered.sort(function(a, b) {
    if (sortBy === 'title-asc')  return (a.t  || '').localeCompare(b.t  || '');
    if (sortBy === 'author-asc') return (a.l2 || '').localeCompare(b.l2 || '');
    if (sortBy === 'year-asc')   return (a.y  || '0').localeCompare(b.y  || '0');
    if (sortBy === 'year-desc')  return (b.y  || '0').localeCompare(a.y  || '0');
    return 0;
  });

  page = 1;
  updateChips();
  updateBadges();
  renderPage();
}

function setSort(val) {
  sortBy = val;
  applyFilters();
}

function setSingle(key, val) {
  if (key === 'cat') {
    selCat = (selCat === val) ? null : val;
    refreshOpts('cat', selCat ? [selCat] : [], false);
  } else {
    selSub = (selSub === val) ? null : val;
    refreshOpts('sub', selSub ? [selSub] : [], false);
  }
  applyFilters();
}

function toggleTopic(val) {
  if (selTopics[val]) delete selTopics[val];
  else selTopics[val] = true;
  refreshOpts('tp', Object.keys(selTopics), true);
  applyFilters();
}

function clearAll() {
  selCat = null;
  selSub = null;
  selTopics = {};
  searchQ = '';
  var si = document.getElementById('search-input');
  var sc = document.getElementById('search-clear');
  if (si) si.value = '';
  if (sc) sc.classList.remove('visible');
  refreshOpts('cat', [], false);
  refreshOpts('sub', [], false);
  refreshOpts('tp',  [], true);
  applyFilters();
}

function refreshOpts(key, activeVals, isSet) {
  var container = document.getElementById('opts-' + key);
  if (!container) return;
  var fopts = container.querySelectorAll('.fopt');
  for (var i = 0; i < fopts.length; i++) {
    var el  = fopts[i];
    var val = el.dataset.val;
    var active;
    if (isSet) {
      active = false;
      for (var j = 0; j < activeVals.length; j++) {
        if (activeVals[j] === val) { active = true; break; }
      }
    } else {
      active = (activeVals.length > 0 && activeVals[0] === val);
    }
    el.classList.toggle('active', active);
  }
}

// ── 7. Search ────────────────────────────────────────────────
function onSearch() {
  var si = document.getElementById('search-input');
  var sc = document.getElementById('search-clear');
  searchQ = si ? si.value.trim() : '';
  if (sc) sc.classList.toggle('visible', searchQ.length > 0);
  clearTimeout(searchTimer);
  searchTimer = setTimeout(applyFilters, 220);
}

function clearSearch() {
  var si = document.getElementById('search-input');
  var sc = document.getElementById('search-clear');
  if (si) si.value = '';
  if (sc) sc.classList.remove('visible');
  searchQ = '';
  applyFilters();
}

// ── 8. Render ────────────────────────────────────────────────
function renderPage() {
  var start     = (page - 1) * CVU_CONFIG.PER_PAGE;
  var slice     = filtered.slice(start, start + CVU_CONFIG.PER_PAGE);
  var container = document.getElementById('papers-container');
  if (!container) return;

  var total = filtered.length;
  var end   = Math.min(page * CVU_CONFIG.PER_PAGE, total);
  var countEl = document.getElementById('result-count');
  if (countEl) {
    countEl.innerHTML = total === 0
      ? 'No papers found'
      : 'Showing <strong>' + (start + 1) + '–' + end + '</strong> of <strong>' + total.toLocaleString() + '</strong> papers';
  }

  if (total === 0) {
    container.className = '';
    container.innerHTML = '<div class="state-box"><h3>No results</h3><p>Try adjusting your filters or search terms.</p></div>';
    var pgEl = document.getElementById('pagination');
    if (pgEl) pgEl.innerHTML = '';
    return;
  }

  container.className = view === 'grid' ? 'cvul-grid' : 'cvul-list';
  var html = '';
  for (var i = 0; i < slice.length; i++) html += cardHTML(slice[i]);
  container.innerHTML = html;
  renderPagination();
  setupObserver();
}

function cardHTML(p) {
  var url   = esc(p.u || '#');
  var isPDF = (p.u || '').toLowerCase().indexOf('.pdf') !== -1;
  var tp    = topicsOf(p);
  var max   = view === 'grid' ? 3 : 2;
  var tags  = '';
  for (var i = 0; i < Math.min(tp.length, max); i++) {
    tags += '<span class="topic-tag">' + esc(tp[i]) + '</span>';
  }
  return '<a class="pcard" href="' + url + '" target="_blank" rel="noopener"' +
    ' data-pid="' + esc(p.id) + '" data-pdfurl="' + (isPDF ? url : '') + '">' +
    '<div class="pcard-thumb thumb-loading" id="th-' + esc(p.id) + '">' +
      '<div class="thumb-ph">' +
        '<div class="thumb-ph-icon">&#x1F4C4;</div>' +
        '<div class="thumb-ph-cat">' + esc(p.c || '') + '</div>' +
      '</div>' +
    '</div>' +
    '<div class="pcard-body">' +
      '<div class="pcard-title">' + esc(p.t) + '</div>' +
      (p.l2 ? '<div class="pcard-authors">' + esc(p.l2) + '</div>' : '') +
      (p.l1 ? '<div class="pcard-source">'   + esc(p.l1) + '</div>' : '') +
      '<div class="pcard-foot">' +
        '<span class="pcard-year">' + esc(p.y || '') + '</span>' +
        (tags ? '<div class="pcard-topics">' + tags + '</div>' : '') +
      '</div>' +
    '</div>' +
  '</a>';
}

// ── 9. PDF Thumbnails ─────────────────────────────────────────
function setupObserver() {
  if (thumbObserver) thumbObserver.disconnect();
  if (!('IntersectionObserver' in window) || typeof pdfjsLib === 'undefined') {
    var els = document.querySelectorAll('.thumb-loading');
    for (var i = 0; i < els.length; i++) els[i].classList.remove('thumb-loading');
    return;
  }
  thumbObserver = new IntersectionObserver(function(entries) {
    for (var i = 0; i < entries.length; i++) {
      var entry = entries[i];
      if (!entry.isIntersecting) continue;
      var thumbEl = entry.target;
      thumbObserver.unobserve(thumbEl);
      var card = thumbEl.closest('.pcard');
      if (!card) continue;
      var pdfUrl = card.dataset.pdfurl;
      var pid    = card.dataset.pid;
      if (!pdfUrl) { thumbEl.classList.remove('thumb-loading'); continue; }
      renderThumb(thumbEl, pdfUrl, pid);
    }
  }, { rootMargin: '300px 0px' });

  var thumbEls = document.querySelectorAll('.pcard-thumb');
  for (var i = 0; i < thumbEls.length; i++) thumbObserver.observe(thumbEls[i]);
}

function renderThumb(container, pdfUrl, pid) {
  if (thumbCache[pid]) {
    showThumbImg(container, thumbCache[pid]);
    return;
  }
  var proxied = CVU_CONFIG.PDF_PROXY + encodeURIComponent(pdfUrl);
  var task = pdfjsLib.getDocument({ url: proxied, disableStream: true, disableRange: true });
  task.promise.then(function(pdf) {
    return pdf.getPage(1);
  }).then(function(pg) {
    var vp  = pg.getViewport({ scale: 1.2 });
    var cvs = document.createElement('canvas');
    cvs.width  = vp.width;
    cvs.height = vp.height;
    return pg.render({ canvasContext: cvs.getContext('2d'), viewport: vp }).promise.then(function() {
      return cvs.toDataURL('image/jpeg', 0.75);
    });
  }).then(function(dataURL) {
    thumbCache[pid] = dataURL;
    showThumbImg(container, dataURL);
  }).catch(function() {
    container.classList.remove('thumb-loading');
  });
}

function showThumbImg(container, dataURL) {
  var img = new Image();
  img.onload = function() {
    container.innerHTML = '';
    container.appendChild(img);
    container.classList.remove('thumb-loading');
  };
  img.style.cssText = 'width:100%;height:100%;object-fit:cover;display:block;';
  img.src = dataURL;
}

// ── 10. Pagination ───────────────────────────────────────────
function renderPagination() {
  var total = filtered.length;
  var pages = Math.ceil(total / CVU_CONFIG.PER_PAGE);
  var pgEl  = document.getElementById('pagination');
  if (!pgEl) return;
  if (pages <= 1) { pgEl.innerHTML = ''; return; }

  var nums = pageNums(page, pages);
  var html = makeBtn('‹', page - 1, page === 1);
  for (var i = 0; i < nums.length; i++) {
    if (nums[i] === '...') html += '<span class="pg-dots">…</span>';
    else html += makeBtn(nums[i], nums[i], false, nums[i] === page);
  }
  html += makeBtn('›', page + 1, page === pages);
  pgEl.innerHTML = html;

  // Wire up pagination clicks
  var btns = pgEl.querySelectorAll('.pg-btn');
  for (var j = 0; j < btns.length; j++) {
    (function(btn) {
      btn.addEventListener('click', function() {
        var n = parseInt(btn.dataset.pg, 10);
        goPage(n);
      });
    })(btns[j]);
  }
}

function makeBtn(label, target, disabled, active) {
  return '<button class="pg-btn' + (active ? ' cur' : '') + '"' +
    (disabled ? ' disabled' : '') +
    ' data-pg="' + target + '">' + label + '</button>';
}

function goPage(n) {
  var pages = Math.ceil(filtered.length / CVU_CONFIG.PER_PAGE);
  if (n < 1 || n > pages) return;
  page = n;
  renderPage();
  window.scrollTo({ top: 0, behavior: 'smooth' });
  var main = document.querySelector('.cvul-main');
  if (main) main.scrollTo({ top: 0, behavior: 'smooth' });
}

function pageNums(cur, total) {
  if (total <= 7) {
    var out = [];
    for (var i = 1; i <= total; i++) out.push(i);
    return out;
  }
  var out = [1];
  if (cur > 3) out.push('...');
  for (var i = Math.max(2, cur - 1); i <= Math.min(total - 1, cur + 1); i++) out.push(i);
  if (cur < total - 2) out.push('...');
  out.push(total);
  return out;
}

// ── 11. Chips (active filter display) ────────────────────────
function updateChips() {
  var row = document.getElementById('chips-row');
  if (!row) return;
  var html = '';
  if (selCat) html += mkChip(selCat, 'cat', selCat);
  if (selSub) html += mkChip(selSub, 'sub', selSub);
  for (var k in selTopics) html += mkChip(k, 'topic', k);
  if (searchQ) html += mkChip('"' + searchQ + '"', 'search', '');
  row.innerHTML = html;

  var xs = row.querySelectorAll('.chip-x');
  for (var i = 0; i < xs.length; i++) {
    (function(el) {
      el.addEventListener('click', function() {
        var type = el.dataset.type;
        var val  = el.dataset.val;
        if (type === 'cat')    setSingle('cat', val);
        else if (type === 'sub')   setSingle('sub', val);
        else if (type === 'topic') toggleTopic(val);
        else if (type === 'search') clearSearch();
      });
    })(xs[i]);
  }
}

function mkChip(label, type, val) {
  return '<span class="chip">' + esc(label) +
    '<span class="chip-x" data-type="' + esc(type) + '" data-val="' + esc(val) + '">×</span></span>';
}

// ── 12. Badges ───────────────────────────────────────────────
function updateBadges() {
  setBadge('badge-cat', selCat ? 1 : 0);
  setBadge('badge-sub', selSub ? 1 : 0);
  setBadge('badge-tp',  Object.keys(selTopics).length);
}

function setBadge(id, n) {
  var el = document.getElementById(id);
  if (!el) return;
  el.textContent = n;
  el.classList.toggle('active', n > 0);
}

// ── 13. View toggle ──────────────────────────────────────────
function setView(v) {
  view = v;
  var gBtn = document.getElementById('vbtn-grid');
  var lBtn = document.getElementById('vbtn-list');
  if (gBtn) gBtn.classList.toggle('active', v === 'grid');
  if (lBtn) lBtn.classList.toggle('active', v === 'list');
  renderPage();
}

// ── 14. Sidebar toggle (mobile) ──────────────────────────────
function openSidebar() {
  var s = document.getElementById('sidebar');
  var o = document.getElementById('cvul-overlay');
  if (s) s.classList.add('open');
  if (o) o.classList.add('open');
}
function closeSidebar() {
  var s = document.getElementById('sidebar');
  var o = document.getElementById('cvul-overlay');
  if (s) s.classList.remove('open');
  if (o) o.classList.remove('open');
}

// ── 15. Section collapse ─────────────────────────────────────
function toggleSection(key) {
  var body  = document.getElementById('body-' + key);
  var arrow = document.getElementById('arrow-' + key);
  if (body)  body.classList.toggle('collapsed');
  if (arrow) arrow.classList.toggle('open');
}

// ── 16. PDF.js loader ────────────────────────────────────────
function loadPdfJs(cb) {
  if (typeof pdfjsLib !== 'undefined') { cb(); return; }
  var s = document.createElement('script');
  s.src = CVU_CONFIG.PDF_JS_SRC;
  s.onload = function() {
    pdfjsLib.GlobalWorkerOptions.workerSrc = CVU_CONFIG.PDF_WORKER_SRC;
    cb();
  };
  s.onerror = cb; // proceed even if PDF.js fails to load
  document.head.appendChild(s);
}

// ── 17. Wire up all DOM event listeners ──────────────────────
function wireEvents() {
  // Search input
  var si = document.getElementById('search-input');
  if (si) si.addEventListener('input', onSearch);

  // Search clear button
  var sc = document.getElementById('search-clear');
  if (sc) sc.addEventListener('click', clearSearch);

  // Clear all filters
  var ca = document.getElementById('clear-all-btn');
  if (ca) ca.addEventListener('click', clearAll);

  // Mobile sidebar toggle
  var mft = document.getElementById('mobile-filter-btn');
  if (mft) mft.addEventListener('click', openSidebar);

  // Overlay close
  var ov = document.getElementById('cvul-overlay');
  if (ov) ov.addEventListener('click', closeSidebar);

  // Sort dropdown
  var ss = document.getElementById('sort-select');
  if (ss) ss.addEventListener('change', function() { setSort(ss.value); });

  // View toggle buttons
  var gBtn = document.getElementById('vbtn-grid');
  var lBtn = document.getElementById('vbtn-list');
  if (gBtn) gBtn.addEventListener('click', function() { setView('grid'); });
  if (lBtn) lBtn.addEventListener('click', function() { setView('list'); });

  // Filter section headers (collapse/expand)
  var hCat = document.getElementById('hd-cat');
  var hSub = document.getElementById('hd-sub');
  var hTp  = document.getElementById('hd-tp');
  if (hCat) hCat.addEventListener('click', function() { toggleSection('cat'); });
  if (hSub) hSub.addEventListener('click', function() { toggleSection('sub'); });
  if (hTp)  hTp.addEventListener('click',  function() { toggleSection('tp'); });
}

// ── 18. DOM-ready polling ─────────────────────────────────────
// Higher Logic loads the JS widget separately from the HTML widget.
// We poll until the key container element exists, then boot.
function domReady(fn) {
  if (document.getElementById('papers-container')) {
    fn();
  } else {
    setTimeout(function() { domReady(fn); }, 150);
  }
}

// ── 19. Boot ─────────────────────────────────────────────────
domReady(function() {
  wireEvents();
  loadPdfJs(function() {
    // Data is appended below as window.__CVU_PAPERS__
    allPapers = window.__CVU_PAPERS__ || [];
    buildSidebar();
    applyFilters();
  });
});

